static int square(int n) {
    return n * n;
}

// Called directly, no object needed:
square(5);

// From within the same class:
square(5);

// From a DIFFERENT class (using Main's square method):
Main.square(5);

public class Main {
    static int doubleIt(int n) {
        return n * 2;
    }

    public static void main(String[] args) {
        System.out.println(doubleIt(21));
        System.out.println(Main.doubleIt(21));
    }
}

